// Нормализуем входные данные для финализатора задачи.

const input = $('Запуск по вызову из другого сценария').item.json

return {
  json: {
    taskKey: String(input.taskKey || '').trim(),
    sessionId: String(input.sessionId || '').trim(),
    chatId: String(input.chatId || '').trim(),
    workerBaseUrl: String(input.workerBaseUrl || '').trim(),
    authorizationHeader: String(input.authorizationHeader || '').trim(),
    sessionStatusPath: String(input.sessionStatusPath || '').trim(),
    messageListPath: String(input.messageListPath || '').trim(),
    latestSentId: String(input.latestSentId || '').trim(),
  },
}

// Проверяем статус сессии: idle = завершена, иначе ещё выполняется.
// Если sessionId начинается с 'claim-' — значит save-session-id не сработал,
// сессия никогда не найдётся в statusMap и задача зависнет навсегда.
// Если сессия не найдена в ответе API — тоже возвращаем ошибку.

const input = $('Разбираем входные данные').item.json
const sessionId = String(input.sessionId || '').trim()

const isClaimToken = sessionId.startsWith('claim-')
if (isClaimToken) {
  return {
    json: {
      isIdle: false,
      sessionError: `Claim token detected as session_id: ${sessionId}. Session ID was never saved after launch.`,
    },
  }
}

const statusMap = $('Получаем статусы сессий').item.json || {}
const sessionStatus = statusMap[sessionId]

if (!sessionStatus || Object.keys(sessionStatus).length === 0) {
  return {
    json: {
      isIdle: false,
      sessionError: `Session ${sessionId} not found in status response.`,
    },
  }
}

const statusType = String(sessionStatus.type || '').trim()
return {
  json: { isIdle: statusType === 'idle' },
}

// Извлекаем из ответа API (с HTML-экранированием для Telegram HTML-режима)

const stripHtml = (str) => String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').trim()

// Извлекаем из ответа API OpenCode текстовый вывод и флаг завершения сессии.
// Алгоритм:
//   1. Фильтруем сообщения сессии: только assistant, сортируем по времени
//   2. Среди новых (ещё не отправленных) сообщений собираем текст → streamProgressText
//   3. Если сессия idle:
//      a. Нет сообщений   → failed
//      b. Есть error      → failed + сообщение ошибки
//      c. Есть текст      → done + ответ
//   4. Если НЕ idle       → running + streamProgress (диспетчер отправит юзеру промежуточный прогресс)
//   5. Если read-status вернул sessionError → failed (сессия не найдена / claimToken не заменён)

const input = $('Разбираем входные данные').item.json
const isIdle = String($('Проверяем статус сессии').item.json.isIdle) === 'true'
const sessionError = String($('Проверяем статус сессии').item.json.sessionError || '').trim()

// Сессия не найдена / claimToken не заменён — сразу failed, без вечного цикла
if (sessionError) {
  return {
    json: {
      resultStatus: 'failed',
      streamProgressText: '',
      latestSentId: input.latestSentId,
      taskCompleted: true,
      replyText: stripHtml(`Задача ${input.taskKey} завершилась ошибкой: ${sessionError}`),
      taskKey: input.taskKey,
    },
  }
}

const latestSentId = input.latestSentId
const rawItems = $('Получаем сообщения сессии').all().map((item) => item.json)
const messages = rawItems.flatMap((item) => Array.isArray(item) ? item : [item]).filter(Boolean)

// Только ответы ассистента, по возрастанию времени создания
const assistantMessages = messages
  .filter((message) => String(message.info?.role || '') === 'assistant')
  .sort((left, right) => Number(left.info?.time?.created || 0) - Number(right.info?.time?.created || 0))

const latestAssistant = assistantMessages[assistantMessages.length - 1] || null

let streamProgressText = ''
let newLatestSentId = latestSentId

// Собираем текст из новых (ещё не виденных) сообщений для промежуточного прогресса
const newMessages = latestSentId
  ? assistantMessages.filter((message) => String(message.info?.id || '') > latestSentId)
  : assistantMessages

for (const message of newMessages) {
  const texts = Array.isArray(message.parts)
    ? message.parts
        .filter((part) => String(part.type || '') === 'text')
        .map((part) => String(part.text || part.content || '').trim())
        .filter(Boolean)
    : []
  if (texts.length > 0) {
    streamProgressText = texts.join('\n').trim()
    newLatestSentId = String(message.info?.id || '').trim()
  }
}

// --- Сессия завершена (idle) ---
if (isIdle) {
  // Нет ни одного ответа от ассистента
  if (!latestAssistant) {
    return {
      json: {
        resultStatus: 'failed',
        streamProgressText: '',
        latestSentId: newLatestSentId,
        taskCompleted: true,
        replyText: stripHtml(`Задача ${input.taskKey} завершилась без итогового ответа OpenCode.`),
        taskKey: input.taskKey,
      },
    }
  }

  // Ассистент вернул ошибку
  const assistantError = latestAssistant.info?.error
  if (assistantError) {
    const errorMessage = String(
      assistantError.data?.message || assistantError.message || assistantError.name || 'OpenCode завершился с ошибкой.'
    )
    return {
      json: {
        resultStatus: 'failed',
        streamProgressText: '',
        latestSentId: newLatestSentId,
        taskCompleted: true,
        replyText: stripHtml(`Задача ${input.taskKey} завершилась ошибкой OpenCode: ${errorMessage}`),
        taskKey: input.taskKey,
      },
    }
  }

  // Успешное завершение: собираем итоговый текст
  const textParts = Array.isArray(latestAssistant.parts)
    ? latestAssistant.parts
        .filter((part) => String(part.type || '') === 'text')
        .map((part) => String(part.text || part.content || '').trim())
        .filter(Boolean)
    : []
  const rawText = textParts.join('\n').trim() || JSON.stringify(latestAssistant)

  return {
    json: {
      resultStatus: 'done',
      streamProgressText: '',
      latestSentId: newLatestSentId,
      taskCompleted: true,
      replyText: stripHtml(`Задача ${input.taskKey} завершена.\n\n${rawText}`),
      taskKey: input.taskKey,
    },
  }
}

// --- Сессия ещё выполняется (НЕ idle) ---
return {
  json: {
    resultStatus: 'running',
    stripHtml(streamProgressText),
    latestSentId: newLatestSentId,
    taskCompleted: false,
    replyText: '',
    taskKey: input.taskKey,
  },
}
